        euint256 ptr;

        if (from == address(0)) {
            // Mint: safely increase total supply.
            (success, ptr) = Nox.safeAdd($._totalSupply, amount);
            ptr = Nox.select(success, ptr, $._totalSupply);
            Nox.allowThis(ptr);
            $._totalSupply = ptr;
